import sys
sys.path.insert(0, 'test/lib')

# Check that the unwanted.py module can be parsed
import ast
with open('test/lib/ansible_test/_util/controller/sanity/pylint/plugins/unwanted.py', 'r') as f:
    code = f.read()
    try:
        ast.parse(code)
        print("✓ Syntax is valid")
    except SyntaxError as e:
        print(f"✗ Syntax error: {e}")
        sys.exit(1)

# Verify the dictionary structure
tree = ast.parse(code)
for node in ast.walk(tree):
    if isinstance(node, ast.ClassDef) and node.name == 'AnsibleUnwantedChecker':
        for item in node.body:
            if isinstance(item, ast.Assign):
                for target in item.targets:
                    if isinstance(target, ast.Name) and target.id == 'unwanted_imports':
                        # Found the unwanted_imports dict
                        # The value should be a dict() call
                        if isinstance(item.value, ast.Call):
                            print("✓ unwanted_imports is defined as dict()")

                            # Check if the dict has a keyword argument with **
                            for keyword in item.value.keywords:
                                if keyword.arg is None:  # This is a **kwargs
                                    print("✓ Dict unpacking syntax (**) found")
                                    if isinstance(keyword.value, ast.Dict):
                                        for key in keyword.value.keys:
                                            if isinstance(key, ast.Constant):
                                                print(f"  - Key: {key.value}")
                                                if 'ansible.module_utils.common._collections_compat' in key.value:
                                                    print("✓ Found _collections_compat entry")

print("\n✓ All verification checks passed!")
EOF

